pub fn alert_messages<'a>(entries: &'a [LogEntry<'a>]) -> Vec<&'a str> {
    entries
        .iter()
        .filter_map(|entry| match entry.level {
            LogLevel::Warn | LogLevel::Error => Some(entry.message),
            LogLevel::Info => None,
        })
        .collect()
}

